// Backend (Express + MongoDB) - RoomController.js
const Room = require('../models/Room');

exports.getRooms = async (req, res, next) => {
  try {
    const rooms = await Room.find();
    res.status(200).json({ rooms });
  } catch (err) {
    next(err);
  }
};
```

